      /* <flatten type="Javascript"> */
function init$GridQuery$(g) {
  var a = g._queryFilterString.split(String.fromCharCode(253));
  g._alterTitle = [null, [['%c', a[0], true], ['%s', g._itemName, true], ['%d1', formatDateView(a[2]), true], ['%d2', formatDateView(a[3]), true]]];
  var x = a[16];
  g._hiddenFields = [
    {Fields: 'gia2, tien2, thue, ck, pt, gia, tien_xuat, lai', Value: (x == '10')},
    {Fields: 'gia_nt2, tien_nt2, thue_nt, ck_nt, pt_nt, gia_nt, tien_nt_x, lai_nt, ma_nt, ty_gia', Value: (x == '20' || x == '10')}
  ];
}
